import React, { useState } from "react";
import arrow from "./arrow.svg";
import { Banner } from "./banner.style";
import { LandingPage, Heading, Arrow } from "./landing.style";
import { ScrollLanding, ScrollUp } from "./scroll.style";
import { Page } from "./webpage.style";

function App() {
  const [landing, setLanding] = useState(true);
  const [page, setPage] = useState(false);
  return (
    <>
      {landing && (
        <ScrollLanding
          id="landing"
          href="#page"
          onClick={() => {
            setPage(true);
            setTimeout(() => {
              setLanding(false);
            }, 750);
          }}
        >
          <LandingPage className="landing-page">
            <Heading> e g a &nbsp; c h e u n g </Heading>
            <Arrow tabIndex={-1} src={arrow} alt="arrow" />
          </LandingPage>
        </ScrollLanding>
      )}

      {page && <Page id="page">

        <ScrollUp href="#landing">
        <Banner />
        </ScrollUp>
      </Page>}
    </>
  );
}

export default App;
